import React, { useState, useRef } from 'react';

const FileUpload = ({ onAnalysisComplete, onError, onLoading }) => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [childAge, setChildAge] = useState(8);
  const [dragActive, setDragActive] = useState(false);
  const fileInputRef = useRef(null);

  const allowedExtensions = ['.wav', '.mp3', '.m4a', '.flac', '.ogg'];
  const maxFileSize = 50 * 1024 * 1024; // 50MB

  const validateFile = (file) => {
    if (!file) return 'No file selected';

    const fileExtension = '.' + file.name.split('.').pop().toLowerCase();
    if (!allowedExtensions.includes(fileExtension)) {
      return `Unsupported file type. Allowed: ${allowedExtensions.join(', ')}`;
    }

    if (file.size > maxFileSize) {
      return 'File size too large. Maximum 50MB allowed.';
    }

    return null;
  };

  const handleFileSelect = (file) => {
    const error = validateFile(file);
    if (error) {
      onError(error);
      return;
    }

    setSelectedFile(file);
    onError(null); // Clear any previous errors
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    const files = e.dataTransfer.files;
    if (files && files[0]) {
      handleFileSelect(files[0]);
    }
  };

  const handleFileInputChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      handleFileSelect(file);
    }
  };

  const handleSubmit = async () => {
    if (!selectedFile) {
      onError('Please select an audio file first');
      return;
    }

    onLoading(true);
    onError(null);

    try {
      const formData = new FormData();
      formData.append('file', selectedFile);
      formData.append('child_age', childAge.toString());

      const response = await fetch('http://localhost:8000/analyze', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || `HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      onAnalysisComplete(result);

    } catch (error) {
      console.error('Analysis error:', error);
      onError(error.message || 'Failed to analyze audio. Please try again.');
    } finally {
      onLoading(false);
    }
  };

  const clearFile = () => {
    setSelectedFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="space-y-6">
      <div className="text-center">
        <h2 className="text-2xl font-semibold text-gray-900 mb-2">Upload Audio File</h2>
        <p className="text-gray-600">Select an audio file containing speech for analysis</p>
      </div>

      {/* File Upload Area */}
      <div
        className={`relative border-2 border-dashed rounded-xl p-8 text-center transition-colors ${
          dragActive
            ? 'border-primary-500 bg-primary-50'
            : selectedFile
            ? 'border-success-500 bg-success-50'
            : 'border-gray-300 hover:border-primary-400'
        }`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input
          ref={fileInputRef}
          type="file"
          accept={allowedExtensions.join(',')}
          onChange={handleFileInputChange}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        />

        <div className="space-y-4">
          {selectedFile ? (
            <>
              <div className="flex items-center justify-center">
                <svg className="w-12 h-12 text-success-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                </svg>
              </div>
              <div>
                <p className="text-lg font-medium text-gray-900">{selectedFile.name}</p>
                <p className="text-sm text-gray-600">
                  {(selectedFile.size / 1024 / 1024).toFixed(2)} MB
                </p>
              </div>
              <button
                onClick={clearFile}
                className="text-red-600 hover:text-red-800 text-sm font-medium"
              >
                Remove file
              </button>
            </>
          ) : (
            <>
              <div className="flex items-center justify-center">
                <svg className="w-12 h-12 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
              </div>
              <div>
                <p className="text-lg font-medium text-gray-900">Drop audio file here</p>
                <p className="text-gray-600">or click to browse</p>
                <p className="text-sm text-gray-500 mt-2">
                  Supported formats: {allowedExtensions.join(', ')} (Max 50MB)
                </p>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Age Selection */}
      <div className="bg-gray-50 rounded-lg p-4">
        <label htmlFor="childAge" className="block text-sm font-medium text-gray-700 mb-2">
          Child's Age
        </label>
        <select
          id="childAge"
          value={childAge}
          onChange={(e) => setChildAge(parseInt(e.target.value))}
          className="block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-primary-500 focus:border-primary-500"
        >
          {Array.from({ length: 7 }, (_, i) => i + 6).map(age => (
            <option key={age} value={age}>{age} years old</option>
          ))}
        </select>
        <p className="text-xs text-gray-500 mt-1">
          Age affects the analysis parameters and reading task expectations
        </p>
      </div>

      {/* Submit Button */}
      <div className="text-center">
        <button
          onClick={handleSubmit}
          disabled={!selectedFile}
          className={`px-8 py-3 rounded-lg font-medium text-white transition-colors ${
            selectedFile
              ? 'bg-primary-600 hover:bg-primary-700 focus:ring-2 focus:ring-primary-500 focus:ring-offset-2'
              : 'bg-gray-400 cursor-not-allowed'
          }`}
        >
          Analyze Speech
        </button>
      </div>
    </div>
  );
};

export default FileUpload;
